    methods

        function v = OctoDouble( in, varargin )
            if nargin == 0
                DoubleDoubleEmpty = DoubleDouble.MakeStatic( [], [] );
                v.v1 = QuadDouble.MakeStatic( DoubleDoubleEmpty, DoubleDoubleEmpty );
                v.v2 = QuadDouble.MakeStatic( DoubleDoubleEmpty, DoubleDoubleEmpty );
                return
            end
            if nargin >= 2
                for i = 1 : length( varargin )
                    in = OctoDouble.Plus( in, varargin{ i } );
                end
            end
            if isa( in, 'OctoDouble' )
                v.v1 = in.v1;
                v.v2 = in.v2;
            elseif isa( in, 'QuadDouble' )
                v.v1 = in;
                v.v2 = QuadDouble.zeros( size( in ) );
            elseif isa( in, 'DoubleDouble' )
                v.v1 = in;
                v.v2 = DoubleDouble.zeros( size( in ) );
            elseif isa( in, 'ED.ExtDouble' )
                C = cell( 1, 4 );
                [ C{ : } ] = ToSumOfDoubles( in );
                v.v1 = DoubleDouble.MakeStatic( C{ 1 }, C{ 2 } );
                v.v2 = DoubleDouble.MakeStatic( C{ 3 }, C{ 4 } );
            else
                v.v1 = DoubleDouble( in );
                v.v2 = DoubleDouble.zeros( size( in ) );
            end

            if nargin == 0
                v.v1 = QuadDouble( [] );
                v.v2 = QuadDouble( [] );
                return
            end
            if nargin >= 2
                for i = 1 : length( varargin )
                    in = OctoDouble.Plus( in, varargin{ i } );
                end
            end
            if isa( in, 'OctoDouble' )
                v.v1 = in.v1;
                v.v2 = in.v2;
            elseif isa( in, 'QuadDouble' )
                v.v1 = in;
                v.v2 = QuadDouble( zeros( size( in ) ) );
            elseif isa( in, 'DoubleDouble' )
                v.v1 = QuadDouble( in );
                v.v2 = QuadDouble( zeros( size( in ) ) );
            else
                v.v1 = QuadDouble( in );
                v.v2 = QuadDouble( zeros( size( in ) ) );
            end
        end

        function v = Promote( ~, a )
            v = OctoDouble( a );
        end

        function n = PromotionOrder( ~ )
            n = 3;
        end

    end

    methods ( Access = protected )

        function v = Make( ~, a1, a2 )
            v = OctoDouble.MakeStatic( a1, a2 );
        end

    end

    methods ( Static )

        function v = ones( varargin )
            v = OctoDouble.MakeStatic( QuadDouble( ones( varargin{:}, 'double' ) ), QuadDouble( zeros( varargin{:}, 'double' ) ) );
        end

        function v = zeros( varargin )
            v = OctoDouble.MakeStatic( QuadDouble( zeros( varargin{:}, 'double' ) ), QuadDouble( zeros( varargin{:}, 'double' ) ) );
        end

        function v = eye( varargin )
            v = OctoDouble.MakeStatic( QuadDouble( eye( varargin{:}, 'double' ) ), QuadDouble( zeros( varargin{:}, 'double' ) ) );
        end

        function v = NaN( varargin )
            v = OctoDouble.MakeStatic( QuadDouble.NaN( varargin{:} ), QuadDouble.NaN( varargin{:} ) );
        end

        function v = Inf( varargin )
            v = OctoDouble.MakeStatic( QuadDouble.Inf( varargin{:} ), QuadDouble.Inf( varargin{:} ) );
        end

        function v = randn( varargin )
            v = ToRandn( OctoDouble.zeros( varargin{:} ) );
        end

        function v = rand( varargin )
            v = ToRand( OctoDouble.zeros( varargin{:} ) );
        end

        function v = randi( imax, varargin )
            v = OctoDouble.MakeStatic( QuadDouble( randi( imax, varargin{:}, 'double' ) ), QuadDouble( zeros( varargin{:}, 'double' ) ) );
        end

    end

    methods ( Static, Access = { ?ED.BaseDoubleDouble, ?ED.BaseExtDoubleProperties } )

        function v = MakeStatic( a1, a2 )
            v = OctoDouble;
            if ~isa( a1, 'QuadDouble' )
                a1 = QuadDouble( a1 );
            end
            if ~isa( a2, 'QuadDouble' )
                a2 = QuadDouble( a2 );
            end
            v.v1 = a1;
            v.v2 = a2;
        end

    end

end
